import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2021年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2021年/核心总结.md","filePath":"01_letters/2021年/核心总结.md"}'),r={name:"01_letters/2021年/核心总结.md"};function o(u,l,h,n,d,s){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2021年巴菲特致股东信核心总结" tabindex="-1">2021年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2021年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2021年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>GAAP净利润898亿美元</li><li>营业利润275亿美元</li><li>每股市场价值增长29.6%，略高于标普500的28.7%</li><li>57年来复合年化收益率20.1%</li></ul><h2 id="四大巨头详解" tabindex="-1">四大巨头详解 <a class="header-anchor" href="#四大巨头详解" aria-label="Permalink to &quot;四大巨头详解&quot;">​</a></h2><h3 id="_1-保险集群" tabindex="-1">1. 保险集群 <a class="header-anchor" href="#_1-保险集群" aria-label="Permalink to &quot;1. 保险集群&quot;">​</a></h3><ul><li>浮存金达1470亿美元（增加90亿美元）</li><li>55年总体承保利润，成本低于零</li><li>Ajit Jain自1986年加入，&quot;几乎完美&quot;的管理者</li><li>浮存金稳定性高，可长期投资</li></ul><h3 id="_2-苹果公司-5-55-股权" tabindex="-1">2. 苹果公司（5.55%股权） <a class="header-anchor" href="#_2-苹果公司-5-55-股权" aria-label="Permalink to &quot;2. 苹果公司（5.55%股权）&quot;">​</a></h3><ul><li>持股市值1611亿美元，成本311亿美元</li><li>持股比例从5.39%增至5.55%（苹果回购所致）</li><li>苹果收益的0.1%相当于1亿美元</li><li>股息7.85亿美元，但伯克希尔&quot;份额&quot;达56亿美元</li><li>赞赏蒂姆·库克的管理才能</li></ul><h3 id="_3-bnsf铁路" tabindex="-1">3. BNSF铁路 <a class="header-anchor" href="#_3-bnsf铁路" aria-label="Permalink to &quot;3. BNSF铁路&quot;">​</a></h3><ul><li>2021年创纪录收益60亿美元</li><li>运送5.35亿吨货物，行驶1.43亿英里</li><li>美国商业的&quot;第一大动脉&quot;</li><li>若改用卡车运输，碳排放将大幅增加</li><li>创纪录收益：老式计算法（扣除所有真实成本）</li></ul><h3 id="_4-伯克希尔能源-91-1-控股" tabindex="-1">4. 伯克希尔能源（91.1%控股） <a class="header-anchor" href="#_4-伯克希尔能源-91-1-控股" aria-label="Permalink to &quot;4. 伯克希尔能源（91.1%控股）&quot;">​</a></h3><ul><li>收益40亿美元，创纪录</li><li>2000年仅1.22亿美元，增长30多倍</li><li>风能、太阳能和输电领域领导者</li><li>非漂绿：自2007年每年如实披露</li><li>将承担美国所需的巨大电力项目</li></ul><h2 id="美国基础设施之王" tabindex="-1">美国基础设施之王 <a class="header-anchor" href="#美国基础设施之王" aria-label="Permalink to &quot;美国基础设施之王&quot;">​</a></h2><ul><li>拥有1580亿美元固定资产（财产、厂房和设备）</li><li>超过任何其他美国公司</li><li>年缴纳联邦所得税33亿美元（占全美1/120）</li><li>每天向财政部缴纳900万美元</li><li>对比：1965年前每天仅缴纳100美元</li></ul><h2 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h2><ul><li>年末市值3507亿美元</li><li>比亚迪持股市值77亿美元（成本2.32亿美元，回报超33倍）</li><li>新增日本商社：伊藤忠、三菱、三井</li><li>清仓雪佛龙（后又在2022年一季度重新买入）</li><li>持有西方石油100亿美元（优先股+认股权证）</li></ul><h2 id="现金与国债" tabindex="-1">现金与国债 <a class="header-anchor" href="#现金与国债" aria-label="Permalink to &quot;现金与国债&quot;">​</a></h2><ul><li>现金及等价物1440亿美元</li><li>其中1200亿美元投资美国国债（一年内到期）</li><li>相当于为美国公众持有的国债提供0.5%融资</li><li>承诺永远持有超过300亿美元现金</li><li>巴菲特个人80%资产在股票，偏好100%配置</li></ul><h2 id="回购政策" tabindex="-1">回购政策 <a class="header-anchor" href="#回购政策" aria-label="Permalink to &quot;回购政策&quot;">​</a></h2><ul><li>两年回购517亿美元（9%流通股）</li><li>持续股东权益增加约10%</li><li>每股浮存金增长25%（从39,387美元到99,497美元）</li><li>2022年继续回购（截至2月23日已回购12亿美元）</li><li>价格敏感：不愿高价回购</li></ul><h2 id="tti与paul-andrews的故事" tabindex="-1">TTI与Paul Andrews的故事 <a class="header-anchor" href="#tti与paul-andrews的故事" aria-label="Permalink to &quot;TTI与Paul Andrews的故事&quot;">​</a></h2><ul><li>Paul Andrews 2021年去世</li><li>1971年用500美元创立TTI（被通用动力裁员）</li><li>首年销售11.2万美元，2021年77亿美元</li><li>选择卖给伯克希尔的原因：保护员工和家庭</li><li>净利润增长673%，员工从2,387增至8,043人</li><li>好运连连：TTI带来BNSF收购机会</li></ul><h2 id="bnsf收购契机" tabindex="-1">BNSF收购契机 <a class="header-anchor" href="#bnsf收购契机" aria-label="Permalink to &quot;BNSF收购契机&quot;">​</a></h2><ul><li>2009年董事会参观TTI，地点选在沃斯堡</li><li>BNSF总部也在沃斯堡</li><li>恰逢BNSF第三季度财报不佳，股价下跌</li><li>11天内完成收购谈判</li><li>预言：百年后仍是关键资产</li></ul><h2 id="美国信念" tabindex="-1">美国信念 <a class="header-anchor" href="#美国信念" aria-label="Permalink to &quot;美国信念&quot;">​</a></h2><ul><li>&quot;永远不要做空美国&quot;</li><li>1942年道琼斯指数99点</li><li>伯克希尔成功依赖美国大本营</li><li>政府是&quot;沉默合伙人&quot;，分享繁荣成果</li></ul><h2 id="合伙人文化" tabindex="-1">合伙人文化 <a class="header-anchor" href="#合伙人文化" aria-label="Permalink to &quot;合伙人文化&quot;">​</a></h2><ul><li>巴菲特从1952年（70年前）开始教授投资课</li><li>查理的&quot;猩猩效应&quot;：教学让思考更清晰</li><li>建议学生：找喜欢的工作和喜欢的人</li><li>伯克希尔员工流动率：每年约一人</li><li>长期股东是&quot;合伙人&quot;，决策时始终牵挂</li></ul><h2 id="股东大会" tabindex="-1">股东大会 <a class="header-anchor" href="#股东大会" aria-label="Permalink to &quot;股东大会&quot;">​</a></h2><ul><li>2022年4月29日-5月1日奥马哈举行</li><li>吉米·巴菲特设计浮筒派对船</li><li>股东可享九折优惠</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><ul><li>&quot;我们是选企业者，不是选股者&quot;</li><li>牛市孕育浮夸的废话</li><li>低利率推高所有生产性资产价格</li><li>信任是最大的回报</li><li>为长期股东&quot;工作&quot;是愉快的事</li></ul>',32)])])}const b=i(r,[["render",o]]);export{c as __pageData,b as default};
